import React, { useState, useEffect } from 'react';
import { getJobs } from '../../services/api';
import ResumeUpload from '../Upload/ResumeUpload';
import RankingsTable from '../Rankings/RankingsTable';
import JobForm from '../JobForm/JobForm';
import './Dashboard.css';

const AdminDashboard = ({ onLogout }) => {
  const [jobs, setJobs] = useState([]);
  const [selectedJob, setSelectedJob] = useState('');
  const [activeTab, setActiveTab] = useState('jobs');

  useEffect(() => {
    loadJobs();
  }, []);

  const loadJobs = async () => {
    try {
      const response = await getJobs();
      setJobs(response.data);
    } catch (error) {
      console.error('Error loading jobs:', error);
    }
  };

  return (
    <div className="dashboard">
      <header>
        <h1>AI Resume Screening System</h1>
        <button onClick={onLogout} className="logout-btn">Logout</button>
      </header>

      <div className="dashboard-content">
        <aside className="sidebar">
          <h3>Job Description</h3>
          <select value={selectedJob} onChange={(e) => setSelectedJob(e.target.value)}>
            <option value="">Select Job...</option>
            {jobs.map(job => (
              <option key={job.id} value={job.id}>{job.title}</option>
            ))}
          </select>

          <div className="tabs">
            <button className={activeTab === 'jobs' ? 'active' : ''} onClick={() => setActiveTab('jobs')}>
              📋 Manage Jobs
            </button>
            <button className={activeTab === 'upload' ? 'active' : ''} onClick={() => setActiveTab('upload')}>
              📤 Upload Resumes
            </button>
            <button className={activeTab === 'rankings' ? 'active' : ''} onClick={() => setActiveTab('rankings')}>
              🏆 View Rankings
            </button>
          </div>
        </aside>

        <main className="main-content">
          {activeTab === 'jobs' && <JobForm onJobCreated={loadJobs} />}
          {activeTab === 'upload' && <ResumeUpload jobId={selectedJob} />}
          {activeTab === 'rankings' && <RankingsTable jobId={selectedJob} />}
        </main>
      </div>
    </div>
  );
};

export default AdminDashboard;
